import software.amazon.awssdk.auth.credentials.{AwsCredentialsProvider, DefaultCredentialsProvider}
import software.amazon.awssdk.regions.Region
import software.amazon.awssdk.services.s3.S3Client

object S3Service {

  // Create a credential provider
  val credentialsProvider: AwsCredentialsProvider = DefaultCredentialsProvider.create()

  // Create an S3 client with the credential provider
  val s3Client: S3Client = S3Client.builder()
    .region(Region.US_EAST_1)
    .credentialsProvider(credentialsProvider)
    .build()

  // Use the S3 client to perform operations
  def uploadFile(bucketName: String, key: String, filePath: String): Unit = {
    s3Client.putObject(bucketName, key, java.io.File.open(filePath))
  }

  def downloadFile(bucketName: String, key: String, filePath: String): Unit = {
    s3Client.getObject(bucketName, key).getObjectContent().transferTo(new java.io.File(filePath))
  }
}